import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ReservationService } from '../reservation/reservation.service';
import { Reservation } from '../models/reservation';
import { Router,ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-reservation-form',
  templateUrl: './reservation-form.component.html',
  styleUrls: ['./reservation-form.component.css']
})
export class ReservationFormComponent {

  reservationForm: FormGroup;

  constructor(private formBuilder: FormBuilder, 
    private reservationService: ReservationService,
    private router: Router,
    private activateRoute: ActivatedRoute) {

    this.reservationForm = this.formBuilder.group({
      guestName: ['', Validators.required],
      guestEmail: ['', [Validators.required, Validators.email]],
      checkInDate: ['', Validators.required],
      checkOutDate: ['', Validators.required],
      roomNumber: ['', [Validators.required, Validators.min(1)]]
    });

     reservationId : number = this.activateRoute.snapshot.paramMap.get('id');
    if (reservationId) {
      const reservation = this.reservationService.getReservation(reservationId);
      if (reservation) {
        this.reservationForm.patchValue(reservation);
      }
    }
  }

  onSubmit() {
    if (this.reservationForm.valid) {
      let reservation: Reservation = this.reservationForm.value;

    const reservationId = this.activateRoute.snapshot.paramMap.get('id');
    if (reservationId) {
      this.reservationService.updateReservation(+reservationId, reservation);
    }else {
      this.reservationService.addReservation(reservation);
    }
      this.router.navigate(['/list']);
    }
  }
}
<app-home></app-home>

<div class="container mt-4">
  <div class="row justify-content-center">
    <div class="col-md-8">
      <div class="card shadow">
        <div class="card-header bg-primary text-white">
          <h3 class="mb-0">Hotel Reservation Form</h3>
        </div>
        <div class="card-body">
          <form [formGroup]="reservationForm" (ngSubmit)="onSubmit()">

            <div class="mb-3">
              <label for="guestName" class="form-label">Guest Name</label>
              <input 
                id="guestName" 
                formControlName="guestName" 
                class="form-control" 
                placeholder="Enter guest name">
              <div class="text-danger small mt-1" *ngIf="reservationForm.get('guestName')?.invalid && reservationForm.get('guestName')?.touched">
                Name is required.
              </div>
            </div>

            <div class="mb-3">
              <label for="guestEmail" class="form-label">Email Address</label>
              <input 
                id="guestEmail" 
                formControlName="guestEmail" 
                type="email" 
                class="form-control" 
                placeholder="guest@example.com">
              <div class="text-danger small mt-1" *ngIf="reservationForm.get('guestEmail')?.invalid && reservationForm.get('guestEmail')?.touched">
                Please enter a valid email.
              </div>
            </div>

            <div class="mb-3">
              <label for="roomNumber" class="form-label">Room Number</label>
              <input 
                id="roomNumber" 
                formControlName="roomNumber" 
                type="number" 
                class="form-control" 
                placeholder="e.g., 101">
              <div class="text-danger small mt-1" *ngIf="reservationForm.get('roomNumber')?.invalid && reservationForm.get('roomNumber')?.touched">
                Room number is required.
              </div>
            </div>

            <div class="row">
              <div class="col-md-6 mb-3">
                <label for="checkInDate" class="form-label">Check-in Date</label>
                <input 
                  id="checkInDate" 
                  formControlName="checkInDate" 
                  type="date" 
                  class="form-control">
                <div class="text-danger small mt-1" *ngIf="reservationForm.get('checkInDate')?.invalid && reservationForm.get('checkInDate')?.touched">
                  Check-in date is required.
                </div>
              </div>

              <div class="col-md-6 mb-3">
                <label for="checkOutDate" class="form-label">Check-out Date</label>
                <input 
                  id="checkOutDate" 
                  formControlName="checkOutDate" 
                  type="date" 
                  class="form-control">
                <div class="text-danger small mt-1" *ngIf="reservationForm.get('checkOutDate')?.invalid && reservationForm.get('checkOutDate')?.touched">
                  Check-out date is required.
                </div>
              </div>
            </div>

            <div class="d-grid gap-2">
              <button type="submit" [disabled]="reservationForm.invalid" class="btn btn-primary btn-lg">
                Submit Reservation
              </button>
            </div>

          </form>
        </div>
      </div>
    </div>
  </div>
</div>
